1	function toKey(x: number, y: number): string {
2	  return `${x},${y}`;
3	}
4	
5	function countNeighbors(x: number, y: number, alive: Set<string>): number {
6	  let count = 0;
7	  for (let dx = -1; dx <= 1; dx++) {
8	    for (let dy = -1; dy <= 1; dy++) {
9	      if (dx === 0 && dy === 0) continue;
10	      if (alive.has(toKey(x + dx, y + dy))) count++;
11	    }
12	  }
13	  return count;
14	}
15	
16	export function nextGeneration(cells: [number, number][]): [number, number][] {
17	  const alive = new Set(cells.map(([x, y]) => toKey(x, y)));
18	
19	  return cells.filter(([x, y]) => {
20	    const neighbors = countNeighbors(x, y, alive);
21	    return neighbors === 2 || neighbors === 3;
22	  });
23	}
